  var ARR_m_clinical_0=[
    { id:"W3-901", dok:3, difficulty:4, q:"Fluid accumulates in the pericardial cavity. What function is directly limited?", a:"Ventricular filling, because the heart is compressed from outside.", tags:["cardiovascular", "clinical-integration", "heart-surfaces", "clinical"], competencies:["cv-surfaces"] },
    { id:"W3-902", dok:3, difficulty:4, q:"A coronary artery is blocked and myocardium dies. What event occurred?", a:"Myocardial infarction.", tags:["cardiovascular", "clinical-integration", "coronary-circulation", "heart-surfaces", "blood-vessels", "clinical"], competencies:["cv-coronary", "cv-surfaces", "bvn-vessel-tunics"] },
    { id:"W3-903", dok:3, difficulty:4, q:"A murmur comes from turbulent backflow through a valve. What valve problem is present?", a:"Valve regurgitation or incompetence.", tags:["cardiovascular", "clinical-integration", "valves", "clinical"], competencies:["cv-valves"] },
    { id:"W3-904", dok:3, difficulty:4, q:"Papillary muscle infarction causes AV valve failure. Why?", a:"Chordae tendineae lose support, so cusps can prolapse during ventricular contraction.", tags:["cardiovascular", "clinical-integration", "valves", "clinical"], competencies:["cv-valves"] },
    { id:"W3-905", dok:3, difficulty:4, q:"Atria and ventricles beat out of step after AV node disease. What disorder category fits?", a:"Heart block.", tags:["cardiovascular", "clinical-integration", "chambers", "conduction-system", "clinical"], competencies:["cv-chambers", "cv-conduction-anat"] },
    { id:"W3-906", dok:3, difficulty:4, q:"Ventricles quiver and pump no blood. What rhythm is this?", a:"Ventricular fibrillation.", tags:["cardiovascular", "clinical-integration", "chambers", "clinical"], competencies:["cv-chambers"] },
    { id:"W3-907", dok:3, difficulty:4, q:"A failing SA node cannot pace normally. What device may help?", a:"Artificial pacemaker.", tags:["cardiovascular", "clinical-integration", "conduction-system", "clinical"], competencies:["cv-conduction-anat"] },
    { id:"W3-911", dok:3, difficulty:4, q:"A vessel has a thick tunica media. What pressure role is it built for?", a:"High-pressure arterial flow and diameter regulation.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-912", dok:3, difficulty:4, q:"A tissue needs rapid filtration. Which capillary type fits?", a:"Fenestrated capillary.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-913", dok:3, difficulty:4, q:"A tissue allows whole cells to pass. Which capillary type fits?", a:"Sinusoid.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-914", dok:3, difficulty:4, q:"A plaque narrows an artery. What happens downstream?", a:"Blood flow decreases.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-915", dok:3, difficulty:4, q:"A thrombus forms on a plaque. Why can symptoms suddenly worsen?", a:"The clot can acutely block the vessel.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-916", dok:3, difficulty:4, q:"A weakened artery wall balloons outward. What disorder is present?", a:"Aneurysm.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-917", dok:3, difficulty:4, q:"Leg pain on walking due to narrowed limb arteries. What disorder fits?", a:"Peripheral artery disease.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-918", dok:3, difficulty:4, q:"Narrowed vessels supplying the heart wall. What disorder fits?", a:"Coronary artery disease.", tags:["cardiovascular", "clinical-integration", "coronary-circulation", "heart-surfaces", "blood-vessels", "clinical"], competencies:["cv-coronary", "cv-surfaces", "bvn-vessel-tunics"] },
    { id:"W3-919", dok:3, difficulty:4, q:"A deep leg clot lodges in a lung artery. What happened?", a:"A DVT became a pulmonary embolism.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "lungs-pleura", "clinical"], competencies:["bvn-vessel-tunics", "resp-lungs-pleura"] },
    { id:"W3-920", dok:3, difficulty:4, q:"A superficial leg vein bulges from backward blood flow. Which structure failed?", a:"Venous valves.", tags:["cardiovascular", "clinical-integration", "valves", "blood-vessels", "clinical"], competencies:["cv-valves", "bvn-vessel-tunics"] },
    { id:"W3-921", dok:3, difficulty:4, q:"Long-term leg valve failure causes swelling and skin changes. What disorder fits?", a:"Chronic venous insufficiency.", tags:["cardiovascular", "clinical-integration", "valves", "blood-vessels", "clinical"], competencies:["cv-valves", "bvn-vessel-tunics"] },
    { id:"W3-922", dok:3, difficulty:4, q:"A fetal atrial shunt remains open after birth. What defect is this?", a:"Patent foramen ovale.", tags:["cardiovascular", "clinical-integration", "chambers", "fetal-circulation", "clinical"], competencies:["cv-chambers", "bvn-fetal-remnants"] },
    { id:"W3-923", dok:3, difficulty:4, q:"A fetal pulmonary trunk-to-aorta shunt remains open after birth. What defect is this?", a:"Patent ductus arteriosus.", tags:["cardiovascular", "clinical-integration", "great-vessels", "blood-vessels", "fetal-circulation", "clinical"], competencies:["bvn-great-vessels", "bvn-vessel-tunics", "bvn-fetal-remnants"] },
    { id:"W3-924", dok:3, difficulty:4, q:"Food enters the laryngeal opening during swallowing. Which structure failed?", a:"Epiglottis.", tags:["respiratory", "clinical-integration", "larynx", "clinical"], competencies:["resp-larynx"] },
    { id:"W3-925", dok:3, difficulty:4, q:"An inhaled object enters the right lung. What anatomy explains this?", a:"The right main bronchus is wider and more vertical.", tags:["respiratory", "clinical-integration", "bronchial-tree", "lungs-pleura", "clinical"], competencies:["resp-tree", "resp-lungs-pleura"] },
    { id:"W3-926", dok:3, difficulty:4, q:"Bronchioles narrow and cause wheezing. What disorder fits?", a:"Asthma.", tags:["respiratory", "clinical-integration", "bronchial-tree", "clinical"], competencies:["resp-tree"] },
    { id:"W3-927", dok:3, difficulty:4, q:"Alveolar walls are permanently destroyed. What disorder fits?", a:"Emphysema.", tags:["respiratory", "clinical-integration", "alveoli-histo", "clinical"], competencies:["resp-histo"] },
    { id:"W3-928", dok:3, difficulty:4, q:"Alveoli are infected and filled with fluid. What disorder fits?", a:"Pneumonia.", tags:["respiratory", "clinical-integration", "lungs-pleura", "alveoli-histo", "clinical"], competencies:["resp-lungs-pleura", "resp-histo"] },
    { id:"W3-929", dok:3, difficulty:4, q:"Air enters the pleural cavity. What disorder fits?", a:"Pneumothorax.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-930", dok:3, difficulty:4, q:"Surfactant is deficient. What alveolar problem becomes likely?", a:"Alveolar collapse.", tags:["respiratory", "clinical-integration", "alveoli-histo", "clinical"], competencies:["resp-histo"] },
    { id:"W3-931", dok:3, difficulty:4, q:"Type I alveolar cells are damaged. What is impaired?", a:"Gas diffusion across the alveolar wall.", tags:["respiratory", "clinical-integration", "alveoli-histo", "clinical"], competencies:["resp-histo"] },
    { id:"W3-932", dok:3, difficulty:4, q:"Type II alveolar cells are damaged. What is reduced?", a:"Surfactant secretion.", tags:["respiratory", "clinical-integration", "alveoli-histo", "clinical"], competencies:["resp-histo"] },
    { id:"W3-933", dok:3, difficulty:4, q:"Alveolar macrophages fail. What defense is weakened?", a:"Removal of inhaled debris and microbes.", tags:["respiratory", "clinical-integration", "alveoli-histo", "clinical"], competencies:["resp-histo"] },
    { id:"W3-934", dok:3, difficulty:4, q:"A lesion is in the lung with a cardiac notch. Which lung?", a:"Left lung.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-935", dok:3, difficulty:4, q:"A lesion is in the lung with three lobes. Which lung?", a:"Right lung.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-936", dok:3, difficulty:4, q:"An airway has C-shaped cartilage rings. What is it?", a:"Trachea.", tags:["respiratory", "clinical-integration", "bronchial-tree", "clinical"], competencies:["resp-tree"] },
    { id:"W3-937", dok:3, difficulty:4, q:"A small airway has smooth muscle and no cartilage. What is it?", a:"Bronchiole.", tags:["respiratory", "clinical-integration", "bronchial-tree", "clinical"], competencies:["resp-tree"] },
    { id:"W3-938", dok:3, difficulty:4, q:"An airway has alveoli budding from its wall. What is it?", a:"Respiratory bronchiole.", tags:["respiratory", "clinical-integration", "bronchial-tree", "alveoli-histo", "clinical"], competencies:["resp-tree", "resp-histo"] },
    { id:"W3-939", dok:3, difficulty:4, q:"Correct: veins always carry oxygen-poor blood.", a:"Incorrect: pulmonary veins carry oxygen-rich blood.", tags:["cardiovascular", "clinical-integration", "great-vessels", "blood-vessels", "clinical"], competencies:["bvn-great-vessels", "bvn-vessel-tunics"] },
    { id:"W3-940", dok:3, difficulty:4, q:"Correct: arteries always carry oxygen-rich blood.", a:"Incorrect: pulmonary arteries carry oxygen-poor blood.", tags:["cardiovascular", "clinical-integration", "great-vessels", "blood-vessels", "clinical"], competencies:["bvn-great-vessels", "bvn-vessel-tunics"] },
    { id:"W3-941", dok:3, difficulty:4, q:"Correct: nerves start each heartbeat.", a:"Incorrect: the conduction system starts the heartbeat; nerves modulate rate.", tags:["cardiovascular", "clinical-integration", "conduction-system", "clinical"], competencies:["cv-conduction-anat"] },
    { id:"W3-942", dok:3, difficulty:4, q:"Correct: gas exchange begins in terminal bronchioles.", a:"Incorrect: gas exchange begins in the respiratory zone.", tags:["respiratory", "clinical-integration", "bronchial-tree", "alveoli-histo", "clinical"], competencies:["resp-tree", "resp-histo"] },
    { id:"W3-943", dok:3, difficulty:4, q:"Correct: capillaries have three tunics.", a:"Incorrect: capillaries have only tunica intima.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-944", dok:3, difficulty:4, q:"Correct: the pleural cavity normally contains air.", a:"Incorrect: it normally contains a thin film of fluid.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-945", dok:3, difficulty:4, q:"Why does systemic hypertension strain the left ventricle?", a:"It must pump against higher arterial pressure.", tags:["cardiovascular", "clinical-integration", "chambers", "blood-vessels", "clinical"], competencies:["cv-chambers", "bvn-vessel-tunics"] },
    { id:"W3-946", dok:3, difficulty:4, q:"Why does aortic stenosis strain the left ventricle?", a:"It obstructs outflow into the aorta.", tags:["cardiovascular", "clinical-integration", "chambers", "great-vessels", "clinical"], competencies:["cv-chambers", "bvn-great-vessels"] },
    { id:"W3-947", dok:3, difficulty:4, q:"Why does pulmonary stenosis strain the right ventricle?", a:"It obstructs outflow into the pulmonary trunk.", tags:["cardiovascular", "clinical-integration", "chambers", "great-vessels", "clinical"], competencies:["cv-chambers", "bvn-great-vessels"] },
    { id:"W3-948", dok:3, difficulty:4, q:"Why does the AV node delay improve pumping?", a:"It lets atria finish emptying before ventricles contract.", tags:["cardiovascular", "clinical-integration", "chambers", "conduction-system", "clinical"], competencies:["cv-chambers", "cv-conduction-anat"] },
    { id:"W3-949", dok:3, difficulty:4, q:"Why do ventricles contract from apex upward?", a:"It pushes blood superiorly toward the outflow vessels.", tags:["cardiovascular", "clinical-integration", "chambers", "blood-vessels", "clinical"], competencies:["cv-chambers", "bvn-vessel-tunics"] },
    { id:"W3-950", dok:3, difficulty:4, q:"Why does emphysema reduce oxygenation?", a:"It reduces alveolar surface area.", tags:["respiratory", "clinical-integration", "alveoli-histo", "clinical"], competencies:["resp-histo"] },
    { id:"W3-951", dok:3, difficulty:4, q:"Why does pneumonia reduce oxygenation?", a:"Fluid and inflammation interfere with diffusion.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-952", dok:3, difficulty:4, q:"Why does asthma affect airflow more than exchange surface?", a:"It narrows bronchioles, which are conducting airways.", tags:["respiratory", "clinical-integration", "bronchial-tree", "clinical"], competencies:["resp-tree"] },
    { id:"W3-953", dok:3, difficulty:4, q:"Why does pneumothorax collapse the lung?", a:"Air breaks the sealed pleural space.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-954", dok:3, difficulty:4, q:"Why is the umbilical vein oxygen-rich?", a:"It carries blood from the placenta to the fetus.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "fetal-circulation", "clinical"], competencies:["bvn-vessel-tunics", "bvn-fetal-remnants"] },
    { id:"W3-955", dok:3, difficulty:4, q:"Why are umbilical arteries oxygen-poor?", a:"They carry fetal blood back to the placenta.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "fetal-circulation", "clinical"], competencies:["bvn-vessel-tunics", "bvn-fetal-remnants"] },
    { id:"W3-956", dok:3, difficulty:4, q:"Why do fetal shunts close after birth?", a:"Lungs inflate and placental oxygen supply ends.", tags:["cardiovascular", "clinical-integration", "fetal-circulation", "lungs-pleura", "clinical"], competencies:["bvn-fetal-remnants", "resp-lungs-pleura"] },
    { id:"W3-957", dok:3, difficulty:4, q:"Why can RCA blockage affect rhythm?", a:"The RCA often supplies the SA and AV nodes.", tags:["cardiovascular", "clinical-integration", "coronary-circulation", "clinical"], competencies:["cv-coronary"] },
    { id:"W3-958", dok:3, difficulty:4, q:"Why can LAD blockage be severe?", a:"It supplies the anterior septum, left ventricle, and apex.", tags:["cardiovascular", "clinical-integration", "chambers", "coronary-circulation", "clinical"], competencies:["cv-chambers", "cv-coronary"] },
    { id:"W3-959", dok:3, difficulty:4, q:"Why can DVT become PE anatomically?", a:"Venous return carries the clot through right heart into pulmonary arteries.", tags:["cardiovascular", "clinical-integration", "great-vessels", "blood-vessels", "clinical"], competencies:["bvn-great-vessels", "bvn-vessel-tunics"] },
    { id:"W3-960", dok:3, difficulty:4, q:"Why are veins used for IVs?", a:"They are superficial, low-pressure, thin-walled, and wide-lumened.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-961", dok:3, difficulty:4, q:"Why are arteries not preferred for routine blood draws?", a:"They are deeper, thicker-walled, and higher pressure.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-962", dok:3, difficulty:4, q:"Why do venous valves matter below the heart?", a:"They oppose gravity and prevent backflow.", tags:["cardiovascular", "clinical-integration", "valves", "blood-vessels", "clinical"], competencies:["cv-valves", "bvn-vessel-tunics"] },
    { id:"W3-963", dok:3, difficulty:4, q:"Why does walking improve venous return?", a:"Skeletal muscles squeeze veins toward the heart.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-964", dok:3, difficulty:4, q:"Why does a portal system matter?", a:"It sends blood through two capillary beds in series for processing.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-965", dok:3, difficulty:4, q:"Why does an anastomosis protect tissue?", a:"It provides an alternate route if one vessel is blocked.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-966", dok:3, difficulty:4, q:"Why do sinusoids fit liver, spleen, and marrow?", a:"They allow large substances or cells to cross.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-967", dok:3, difficulty:4, q:"Why are continuous capillaries less leaky?", a:"They have an unbroken endothelial lining.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-968", dok:3, difficulty:4, q:"Why do fenestrated capillaries fit kidney and intestine?", a:"They support rapid filtration or absorption.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-970", dok:3, difficulty:4, q:"Why do gap junctions matter in myocardium?", a:"They spread electrical signals cell to cell.", tags:["cardiovascular", "clinical-integration", "heart-surfaces", "clinical"], competencies:["cv-surfaces"] },
    { id:"W3-971", dok:3, difficulty:4, q:"Why do desmosomes matter in myocardium?", a:"They keep cells attached during forceful contraction.", tags:["cardiovascular", "clinical-integration", "heart-surfaces", "clinical"], competencies:["cv-surfaces"] },
    { id:"W3-972", dok:3, difficulty:4, q:"Why can endocardial damage affect valves?", a:"Endocardium covers valves and lines chambers.", tags:["cardiovascular", "clinical-integration", "chambers", "valves", "heart-surfaces", "clinical"], competencies:["cv-chambers", "cv-valves", "cv-surfaces"] },
    { id:"W3-973", dok:3, difficulty:4, q:"Why is fossa ovalis a fetal remnant landmark?", a:"It marks where the foramen ovale was.", tags:["cardiovascular", "clinical-integration", "heart-surfaces", "fetal-circulation", "clinical"], competencies:["cv-surfaces", "bvn-fetal-remnants"] },
    { id:"W3-974", dok:3, difficulty:4, q:"Why does the ductus arteriosus bypass fetal lungs?", a:"Fetal lungs are collapsed and not used for gas exchange.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "fetal-circulation", "lungs-pleura", "alveoli-histo", "clinical"], competencies:["bvn-vessel-tunics", "bvn-fetal-remnants", "resp-lungs-pleura", "resp-histo"] },
    { id:"W3-975", dok:3, difficulty:4, q:"Why does the ductus venosus bypass fetal liver?", a:"Placenta handles much filtering before birth.", tags:["cardiovascular", "clinical-integration", "fetal-circulation", "clinical"], competencies:["bvn-fetal-remnants"] },
    { id:"W3-976", dok:3, difficulty:4, q:"Why can atherosclerosis cause CAD, PAD, or stroke?", a:"The same plaque process causes different diseases depending on location.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-977", dok:3, difficulty:4, q:"Why does an aneurysm rupture risk matter?", a:"A weakened high-pressure artery wall can burst.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-978", dok:3, difficulty:4, q:"Why is stroke time-sensitive?", a:"Brain tissue begins dying within minutes of lost blood supply.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-981", dok:3, difficulty:4, q:"Why does ventricular fibrillation need defibrillation?", a:"A shock can stop chaotic signals so SA node can restart rhythm.", tags:["cardiovascular", "clinical-integration", "conduction-system", "clinical"], competencies:["cv-conduction-anat"] },
    { id:"W3-982", dok:3, difficulty:4, q:"Why is atrial fibrillation usually less immediately fatal than ventricular fibrillation?", a:"Ventricles may still pump blood.", tags:["cardiovascular", "clinical-integration", "chambers", "clinical"], competencies:["cv-chambers"] },
    { id:"W3-983", dok:3, difficulty:4, q:"Why are AV valves supported but semilunar valves are not?", a:"AV valves face ventricular pressure that could invert cusps.", tags:["cardiovascular", "clinical-integration", "valves", "clinical"], competencies:["cv-valves"] },
    { id:"W3-984", dok:3, difficulty:4, q:"Why does one-way valve flow matter?", a:"Backflow reduces forward cardiac output.", tags:["cardiovascular", "clinical-integration", "valves", "clinical"], competencies:["cv-valves"] },
    { id:"W3-985", dok:3, difficulty:4, q:"Why does the left ventricle have the thickest wall?", a:"It pumps blood through systemic circulation.", tags:["cardiovascular", "clinical-integration", "chambers", "clinical"], competencies:["cv-chambers"] },
    { id:"W3-986", dok:3, difficulty:4, q:"Why is the right ventricle thinner than the left?", a:"It pumps only to the nearby lungs.", tags:["cardiovascular", "clinical-integration", "chambers", "lungs-pleura", "clinical"], competencies:["cv-chambers", "resp-lungs-pleura"] },
    { id:"W3-987", dok:3, difficulty:4, q:"Why are capillary walls thin?", a:"To allow exchange.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "clinical"], competencies:["bvn-vessel-tunics"] },
    { id:"W3-988", dok:3, difficulty:4, q:"Why does the respiratory membrane need to be thin?", a:"To minimize diffusion distance.", tags:["respiratory", "clinical-integration", "alveoli-histo", "clinical"], competencies:["resp-histo"] },
    { id:"W3-989", dok:3, difficulty:4, q:"Why does the pleural cavity need fluid?", a:"To let lungs glide during expansion.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-990", dok:3, difficulty:4, q:"Why is the left lung smaller?", a:"It accommodates the heart via the cardiac notch.", tags:["respiratory", "clinical-integration", "lungs-pleura", "clinical"], competencies:["resp-lungs-pleura"] },
    { id:"W3-991", dok:3, difficulty:4, q:"Why does the larynx matter beyond voice?", a:"It protects the airway during swallowing.", tags:["respiratory", "clinical-integration", "larynx", "clinical"], competencies:["resp-larynx"] },
    { id:"W3-992", dok:3, difficulty:4, q:"Why do conchae improve air conditioning?", a:"They swirl air over warm, moist mucosa.", tags:["cardiovascular", "clinical-integration", "clinical"], competencies:[] },
    { id:"W3-993", dok:3, difficulty:4, q:"Why does the nasal vestibule filter large particles?", a:"It contains coarse hairs called vibrissae.", tags:["cardiovascular", "clinical-integration", "clinical"], competencies:[] },
    { id:"W3-994", dok:3, difficulty:4, q:"Why do bronchioles regulate airflow?", a:"Their smooth muscle changes airway diameter.", tags:["respiratory", "clinical-integration", "bronchial-tree", "clinical"], competencies:["resp-tree"] },
    { id:"W3-995", dok:3, difficulty:4, q:"Why do terminal bronchioles not exchange gas?", a:"They are still part of the conducting zone.", tags:["respiratory", "clinical-integration", "bronchial-tree", "clinical"], competencies:["resp-tree"] },
    { id:"W3-996", dok:3, difficulty:4, q:"Why do alveoli have pulmonary capillaries wrapped around them?", a:"To bring blood close to air for gas exchange.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "alveoli-histo", "clinical"], competencies:["bvn-vessel-tunics", "resp-histo"] },
    { id:"W3-997", dok:3, difficulty:4, q:"Why are respiratory disorders structurally predictable?", a:"They either block airflow or damage the exchange surface.", tags:["cardiovascular", "clinical-integration", "clinical"], competencies:[] },
    { id:"W3-998", dok:3, difficulty:4, q:"Week 3 synthesis: how do heart, vessels, and lungs work together?", a:"Heart pumps blood, vessels distribute and exchange it, and lungs bring air to alveoli for gas exchange.", tags:["cardiovascular", "clinical-integration", "blood-vessels", "lungs-pleura", "alveoli-histo", "clinical"], competencies:["bvn-vessel-tunics", "resp-lungs-pleura", "resp-histo"] }
  ];
